import{_ as t,a,b as n,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Telegram Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/telegram.md","filePath":"ta/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"ta/upload/telegram.md"};function h(p,e,m,b,g,u){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-channel-சேர்க்கவும்" tabindex="-1">Telegram Channel சேர்க்கவும் <a class="header-anchor" href="#telegram-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Telegram Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>Telegram account</td><td>bot மற்றும் storage channel உருவாக்க</td></tr><tr><td><code>@BotFather</code></td><td>Telegram bot உருவாக்க</td></tr><tr><td>Telegram channel</td><td>files சேமிக்கப்படும் இறுதி இடம்</td></tr><tr><td><code>@userinfobot</code></td><td>channel <code>Chat ID</code> அறிய</td></tr></tbody></table><h2 id="எங்கு-சேர்ப்பது" tabindex="-1">எங்கு சேர்ப்பது <a class="header-anchor" href="#எங்கு-சேர்ப்பது" aria-label="Permalink to &quot;எங்கு சேர்ப்பது&quot;">​</a></h2><ol><li>System Settings திறக்கவும்.</li><li>Upload Settings-க்கு செல்லவும்.</li><li>மேல் வலது மூலையில் Add Channel கிளிக் செய்யவும்.</li><li><code>Telegram</code> தேர்வு செய்யவும்.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>பயன்பாடு</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>இந்த channel-க்கு எளிதாக அறியக்கூடிய பெயர், உதா. <code>Telegram Primary</code>.</td><td>Required</td></tr><tr><td>Active</td><td>channel-ஐ enable அல்லது disable செய்கிறது.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Telegram bot token.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>Telegram channel ID.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Telegram access நிலையாக இல்லாதபோது மட்டும் பயன்படுத்தவும். <code>https://</code> உடன் முழு proxy URL கொடுக்கவும்.</td><td>Optional</td></tr><tr><td>Remark</td><td>பின்னர் maintenance-க்கு குறிப்புகள்.</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-telegram-bot-உருவாக்கவும்" tabindex="-1">1. Telegram Bot உருவாக்கவும் <a class="header-anchor" href="#_1-telegram-bot-உருவாக்கவும்" aria-label="Permalink to &quot;1. Telegram Bot உருவாக்கவும்&quot;">​</a></h3><ol><li>Telegram திறந்து <code>@BotFather</code> தேடவும்.</li><li>chat திறந்து <code>Start</code> கிளிக் செய்யவும்.</li><li><code>/newbot</code> அனுப்பவும்.</li><li>bot display name கேட்கும்போது உள்ளிடவும்.</li><li>bot username உள்ளிடவும். பொதுவாக username <code>bot</code> என முடிவது வேண்டும்.</li><li>bot உருவானதும் <code>@BotFather</code> bot token தரும்.</li></ol><p>அந்த token-ஐ ImgBed-ல் <code>Bot Token</code> ஆக நிரப்ப வேண்டும்.</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-channel-உருவாக்கவும்" tabindex="-1">2. Channel உருவாக்கவும் <a class="header-anchor" href="#_2-channel-உருவாக்கவும்" aria-label="Permalink to &quot;2. Channel உருவாக்கவும்&quot;">​</a></h3><ol><li>Telegram-ல் New Channel கிளிக் செய்யவும்.</li><li>channel name உள்ளிடவும்.</li><li>channel creation முடிக்கவும்.</li></ol><p>Public மற்றும் private channels இரண்டும் பயன்படுத்தலாம்.</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-bot-ஐ-channel-ல்-சேர்க்கவும்" tabindex="-1">3. Bot-ஐ Channel-ல் சேர்க்கவும் <a class="header-anchor" href="#_3-bot-ஐ-channel-ல்-சேர்க்கவும்" aria-label="Permalink to &quot;3. Bot-ஐ Channel-ல் சேர்க்கவும்&quot;">​</a></h3><ol><li>உருவாக்கிய channel திறக்கவும்.</li><li>channel settings திறக்கவும்.</li><li>member அல்லது administrator சேர்க்கும் இடத்தைத் திறக்கவும்.</li><li>உருவாக்கிய bot username தேடவும்.</li><li>bot-ஐ channel-ல் சேர்க்கவும்.</li></ol><p>upload நம்பகமாக இயங்க bot-க்கு administrator permissions கொடுப்பது நல்லது.</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-channel-id-பெறவும்" tabindex="-1">4. Channel ID பெறவும் <a class="header-anchor" href="#_4-channel-id-பெறவும்" aria-label="Permalink to &quot;4. Channel ID பெறவும்&quot;">​</a></h3><ol><li>Telegram-ல் <code>@userinfobot</code> தேடவும். display name பொதுவாக <code>User Info - Get ID - IDbot</code>.</li><li>chat திறந்து <code>Start</code> கிளிக் செய்யவும்.</li><li>bot options-ல் <code>Channel</code> தேர்வு செய்யவும்.</li><li>message picker-ல் target channel தேர்வு செய்து <code>@userinfobot</code>-க்கு அனுப்பவும்.</li><li>result வந்ததும் <code>Id: -100...</code> என தொடங்கும் number-ஐ copy செய்யவும்.</li></ol><p><code>-100</code> என தொடங்கும் number தான் ImgBed-க்கு தேவையான <code>Session ID (Chat ID)</code>.</p><p><img src="'+l+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-imgbed-ல்-telegram-channel-நிரப்பவும்" tabindex="-1">5. ImgBed-ல் Telegram Channel நிரப்பவும் <a class="header-anchor" href="#_5-imgbed-ல்-telegram-channel-நிரப்பவும்" aria-label="Permalink to &quot;5. ImgBed-ல் Telegram Channel நிரப்பவும்&quot;">​</a></h3><p>configuration dialog-க்கு திரும்பி fields-ஐ இவ்வாறு நிரப்பவும்:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>custom channel name, உதா. <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> கொடுத்த bot token.</td></tr><tr><td>Session ID (Chat ID)</td><td><code>@userinfobot</code> கொடுத்த <code>-100...</code> number.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>தேவைப்பட்டால் மட்டும், உதா. <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>optional notes.</td></tr></tbody></table><p>முடிந்ததும் Save கிளிக் செய்யவும்.</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="எப்படி-verify-செய்வது" tabindex="-1">எப்படி Verify செய்வது <a class="header-anchor" href="#எப்படி-verify-செய்வது" aria-label="Permalink to &quot;எப்படி Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>சரிபார்ப்பு</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save செய்த பிறகு Upload Settings-ல் Telegram channel card காணப்பட வேண்டும்.</td></tr><tr><td>Channel can be enabled</td><td>Active switch on ஆகவே இருக்க வேண்டும்.</td></tr><tr><td>Configuration is saved</td><td>detail view-ல் Bot Token மற்றும் Chat ID saved என காண வேண்டும்.</td></tr><tr><td>Upload works</td><td>test image upload செய்து target Telegram channel-ல் வந்ததா பார்க்கவும்.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather மூலம் bot உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; Bot Token சேமிக்கவும்</span></span>
<span class="line"><span>-&gt; Telegram channel உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; bot-ஐ channel-ல் சேர்த்து administrator permissions கொடுக்கவும்</span></span>
<span class="line"><span>-&gt; @userinfobot தேடி Channel தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; channel message ஒன்றை @userinfobot-க்கு forward செய்யவும்</span></span>
<span class="line"><span>-&gt; திரும்ப வரும் Id: -100... copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் Bot Token மற்றும் Chat ID நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save செய்து test image upload செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=r(c,[["render",h]]);export{_ as __pageData,T as default};
